import os
from google.cloud import storage

def load_latest_model_from_gcs():
    bucket_name = "your-bucket-name"
    model_path = os.getenv("MODEL_PATH", "default/path")
    
    client = storage.Client()
    bucket = client.bucket(bucket_name)
    blobs = bucket.list_blobs(prefix=model_path, delimiter="/")
    
    latest_blob = None
    latest_timestamp = 0
    
    for blob in blobs:
        if blob.name.endswith(".pb"):  # Assuming model files are .pb
            timestamp = int(blob.last_modified.timestamp())
            if timestamp > latest_timestamp:
                latest_timestamp = timestamp
                latest_blob = blob
    
    if latest_blob:
        local_path = f"/tmp/{latest_blob.name.split('/')[-1]}"
        latest_blob.download_to_filename(local_path)
        print(f"Loaded model from GCS: {local_path}")
        return local_path
    else:
        raise FileNotFoundError("No model found in the specified path.")

if __name__ == "__main__":
    try:
        model_path = load_latest_model_from_gcs()
        # Add code to use the loaded model for inference here
    except Exception as e:
        print(f"Error loading model: {e}")